challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is malfunctioning, causing a drop in media packets for active calls, which is observed as a collapse in the UPF activity metric and high packet loss reported by the RTPEngine.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=upf",
          "expected_if_hypothesis_holds": "UPF's drop counters, such as `upf_gtp_packets_dropped` or `upf_n6_tx_errors`, show a high or increasing value.",
          "falsifying_observation": "The UPF's drop or error counters are zero or at their baseline values.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "Data plane gauges show low or zero packets/sec outbound from the UPF on the N6 interface, despite active GTP sessions on N3.",
          "falsifying_observation": "Data plane gauges show healthy packet rates outbound from the UPF on the N6 interface.",
          "conflates_with": []
        },
        {
          "tool": "get_network_status",
          "args_hint": "nf=upf",
          "expected_if_hypothesis_holds": "The UPF container is in a 'running' state.",
          "falsifying_observation": "The UPF container has exited or is in a restart loop.",
          "conflates_with": []
        }
      ],
      "notes": "This plan addresses the linter feedback (A2) by rephrasing expectations to be about observable metric values rather than their internal source."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The RTPEngine is the source of the media plane failure, dropping incoming RTP packets from the UPF, leading to a high reported packet loss ratio.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=rtpengine",
          "expected_if_hypothesis_holds": "RTPEngine's error counters, such as `rtpengine_errors` or `rtpengine_nomem`, are elevated or increasing.",
          "falsifying_observation": "RTPEngine's error counters are all zero or at their baseline values.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "Data plane gauges for RTPEngine show high packet loss and a low Media Opinion Score (MOS).",
          "falsifying_observation": "Data plane gauges for RTPEngine show low packet loss and a healthy Media Opinion Score (MOS).",
          "conflates_with": []
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container=rtpengine",
          "expected_if_hypothesis_holds": "The rtpengine process is listening on its expected RTP/RTCP ports.",
          "falsifying_observation": "The rtpengine process is not listening on one or more of its expected RTP/RTCP ports.",
          "conflates_with": []
        }
      ],
      "notes": "This plan addresses the linter feedback (A2) by removing mechanism-scoping language from probe expectations."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "There is a network connectivity issue on the RTP media path between the UPF and the RTPEngine, causing packet loss, even though the high-level topology shows the link as active.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from=upf, to_ip=rtpengine",
          "expected_if_hypothesis_holds": "High RTT or significant packet loss is observed.",
          "falsifying_observation": "Low RTT and no packet loss is observed. When combined with the partner probe, this suggests the path is healthy.",
          "conflates_with": [
            "A fault within the UPF container's networking stack",
            "A fault within the RTPEngine container's networking stack"
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from=pcscf, to_ip=rtpengine",
          "expected_if_hypothesis_holds": "Low RTT and no packet loss is observed, indicating the RTPEngine is reachable from other NFs and the issue is specific to the path from the UPF.",
          "falsifying_observation": "High RTT or significant packet loss is observed, suggesting the problem is with the RTPEngine itself or a common network path, not just the UPF-RTPEngine link.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "Gauges show packets being sent by UPF (e.g. n6_tx_packets) but not received by RTPEngine (e.g. rtp_rx_packets), with high loss reported by RTPEngine.",
          "falsifying_observation": "Gauges show a matching number of packets sent by UPF and received by RTPEngine, with low reported loss.",
          "conflates_with": []
        }
      ],
      "notes": "This plan addresses the linter feedback (A1) by including a partner probe for the compositional `measure_rtt` tool to help disambiguate the source of potential packet loss or latency."
    }
  ]
}

